export function initialize(sentinel, dotNetRef) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnSentinelVisible');
        }
    }, { rootMargin: '128px' });

    observer.observe(sentinel);
    return observer;
}

export function dispose(observer) {
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinel" class="infinite-scroll-sentinel">
            @if (_loading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span>Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinel;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _loading;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            await SetupObserver();
        }
    }

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousHasMore = HasMore;
        await base.SetParametersAsync(parameters);

        // Reconnect observer when HasMore transitions from false to true
        if (!previousHasMore && HasMore && _observer is null && _module is not null)
        {
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        _module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");
        _dotNetRef ??= DotNetObjectReference.Create(this);
        _observer = await _module.InvokeAsync<IJSObjectReference>(
            "initialize", _sentinel, _dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_loading || !HasMore) return;

        _loading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _loading = false;
        StateHasChanged();

        if (!HasMore)
        {
            await DisposeObserver();
        }
    }

    private async Task DisposeObserver()
    {
        if (_observer is not null && _module is not null)
        {
            await _module.InvokeVoidAsync("dispose", _observer);
            _observer = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeObserver();
        _dotNetRef?.Dispose();

        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

